// // This module implements a register circuit with an 8-bit output capable of loading new data or performing a left shift. It is controlled by a clock (clk) and can be reset asynchronously. When reset is asserted, the output is set to zero. If the load (ld) signal is activated, the current input value is latched into the output. If the left shift control (lshct) signal is asserted instead, the output value is shifted left by one bit on the next clock edge.
module top_module(output reg [7:0] out, input [7:0] in, input ld,rshct,clk,reset);always @(posedge clk, posedge reset)
begin
    if(reset)
        out <= 0;
    else if(ld)
        out <= in;
    else if(rshct)
        out <= out >> 1;
end
endmodule
